```rust
impl Model for MyApp {
    fn update(&mut self, msg: Event) -> Cmd<Event> {
        match msg {
            Event::Resize { width, height } => {
                // Recalculate layouts
                // Re-render at new size
                self.size = (width, height);
                Cmd::none()
            }
            Event::Focus(gained) => {
                // Update focus state
                // Maybe pause/resume animations
